import type { MaterialGroupDto } from '../services/master/models';

/** Ant Design Table `indentSize={20}` — tree row padding. */
export const MATERIAL_GROUP_INDENT_PX = 20;

/**
 * Flatten material groups depth-first (parent → children) for tree table display.
 * Siblings sorted by `code`.
 */
export function flattenMaterialGroupTree(items: MaterialGroupDto[]): MaterialGroupDto[] {
  const childrenOf = new Map<string | null, MaterialGroupDto[]>();
  for (const g of items) {
    const key = g.parentId ?? null;
    const list = childrenOf.get(key);
    if (list) list.push(g);
    else childrenOf.set(key, [g]);
  }
  for (const list of childrenOf.values()) {
    list.sort((a, b) => a.code.localeCompare(b.code, 'vi'));
  }

  const out: MaterialGroupDto[] = [];
  const visit = (parentId: string | null) => {
    for (const g of childrenOf.get(parentId) ?? []) {
      out.push(g);
      visit(g.id);
    }
  };
  visit(null);
  return out;
}

export function materialGroupRowIndent(level?: number): number {
  return Math.max(0, (level ?? 1) - 1) * MATERIAL_GROUP_INDENT_PX;
}
